//\n//  LoadingView.swift\n//  DeviceRadar\n//\n//  Created by DeviceRadar Team.\n//  Copyright © 2026 LethalLethes. All rights reserved.\n//\n\nimport SwiftUI\n\n/// Loading animation displayed while collecting signals.\nstruct LoadingView: View {\n    @State private var rotation = 0.0\n    \n    var body: some View {\n        VStack(spacing: 16) {\n            ZStack {\n                // Background circle\n                Circle()\n                    .stroke(Color.secondary.opacity(0.15), lineWidth: 3)\n                    .frame(width: 56, height: 56)\n                \n                // Animated progress circle\n                Circle()\n                    .trim(from: 0, to: 0.25)\n                    .stroke(\n                        LinearGradient(\n                            colors: [Color(hex: \"4ADE80\"), Color(hex: \"22D3EE\")],\n                            startPoint: .leading,\n                            endPoint: .trailing\n                        ),\n                        style: StrokeStyle(lineWidth: 3, lineCap: .round)\n                    )\n                    .frame(width: 56, height: 56)\n                    .rotationEffect(.degrees(rotation))\n                    .onAppear {\n                        withAnimation(.linear(duration: 1).repeatForever(autoreverses: false)) {\n                            rotation = 360\n                        }\n                    }\n            }\n            \n            Text(\"Siqnallar toplanır...\")\n                .font(.subheadline)\n                .foregroundColor(.secondary)\n        }\n    }\n}\n\n// MARK: - Preview\n\n#if DEBUG\nstruct LoadingView_Previews: PreviewProvider {\n    static var previews: some View {\n        LoadingView()\n    }\n}\n#endif\n